from dataclasses import dataclass, asdict
from datetime import datetime
from collections import defaultdict

from .config import Config, HardeningConfig

@dataclass
class SystemError:
    """Represents a system error for tracking and recovery"""
    timestamp: float
    component: str
    error_type: str
    error_message: str
    severity: str  # "low", "medium", "high", "critical"
    recovery_attempted: bool = False
    recovery_successful: bool = False

@dataclass
class KillSwitch:
    """Represents a system kill switch"""
    name: str
    description: str
    trigger_condition: str
    enabled: bool = True
    triggered: bool = False
    trigger_count: int = 0

class SystemHardeningManager:
    """Centralized system hardening and error handling manager"""

    def __init__(self, config: Config):
        self.config = config
        self.hardening_config = config.hardening

        # Error tracking
        self.error_history: List[SystemError] = []
        self.component_error_counts = defaultdict(int)
        self.consecutive_error_counts = defaultdict(int)

        # Kill switches
        self.kill_switches: Dict[str, KillSwitch] = {}
        self.global_kill_switch_triggered = False

        # Recovery mechanisms
        self.recovery_handlers: Dict[str, Callable] = {}
        self.safe_mode_active = False
        self.emergency_mode_active = False

        # Monitoring
        self.monitoring_active = True
        self.monitoring_thread = None

        # Backup management
        self.backup_directory = Path('logs/hardening_backups')
        self.backup_directory.mkdir(parents=True, exist_ok=True)

        # Initialize hardening systems
        self._initialize_kill_switches()
        self._setup_signal_handlers()
        self._start_monitoring()

    def _initialize_kill_switches(self):
        """Initialize system kill switches"""
        if not self.hardening_config.enable_kill_switches:
            return

        # MVCO background thread kill switch
        self.kill_switches['mvco_thread'] = KillSwitch(
            name='mvco_thread',
            description='MVCO background thread safety switch',
            trigger_condition='consecutive_mvco_errors >= 5'
        )

        # Model pull failure kill switch
        self.kill_switches['model_pull'] = KillSwitch(
            name='model_pull',
            description='Model pulling failure safety switch',
            trigger_condition='consecutive_pull_failures >= 3'
        )

        # Memory usage kill switch
        self.kill_switches['memory_usage'] = KillSwitch(
            name='memory_usage',
            description='Memory usage safety switch',
            trigger_condition='memory_usage > 90%'
        )

        # Global system kill switch
        self.kill_switches['global_emergency'] = KillSwitch(
            name='global_emergency',
            description='Global emergency system shutdown',
            trigger_condition='critical_errors >= 10'
        )

    def _setup_signal_handlers(self):
        """Setup signal handlers for graceful shutdown"""
        def signal_handler(signum, frame):
            print(f"Hardening Manager: Received signal {signum}, initiating graceful shutdown")
            self.trigger_graceful_shutdown()

        signal.signal(signal.SIGINT, signal_handler)
        signal.signal(signal.SIGTERM, signal_handler)

    def _start_monitoring(self):
        """Start the monitoring thread"""
        if self.monitoring_thread is None or not self.monitoring_thread.is_alive():
            self.monitoring_thread = threading.Thread(
                target=self._monitoring_loop,
                daemon=True,
                name="HardeningMonitor"
            )
            self.monitoring_thread.start()

    def _monitoring_loop(self):
        """Main monitoring loop for system health"""
        while self.monitoring_active:
            try:
                # Check system health
                self._check_memory_usage()
                self._check_error_patterns()
                self._evaluate_kill_switches()

                # Sleep for monitoring interval
                time.sleep(5)

            except Exception as e:
                print(f"Hardening Monitor error: {e}")
                time.sleep(10)  # Longer sleep on error

    def _check_memory_usage(self):
        """Check system memory usage"""
        try:
            import psutil
            memory_percent = psutil.virtual_memory().percent

            if memory_percent > 90:
                self.report_error(
                    component='system',
                    error_type='memory_usage',
                    error_message=f'High memory usage: {memory_percent}%',
                    severity='high'
                )

                # Trigger memory kill switch if configured
                if 'memory_usage' in self.kill_switches:
                    self._trigger_kill_switch('memory_usage')

        except Exception as e:
            print(f"Memory check failed: {e}")

    def _check_error_patterns(self):
        """Check for dangerous error patterns"""
        # Check consecutive errors per component
        for component, count in self.consecutive_error_counts.items():
            if count >= self.hardening_config.max_consecutive_errors:
                print(f"Hardening: Component {component} exceeded max consecutive errors ({count})")
                self._trigger_safe_mode(f"Excessive errors in {component}")

    def _evaluate_kill_switches(self):
        """Evaluate all kill switch conditions"""
        for switch_name, kill_switch in self.kill_switches.items():
            if not kill_switch.enabled or kill_switch.triggered:
                continue

            # Evaluate trigger conditions
            should_trigger = False

            if switch_name == 'mvco_thread':
                mvco_errors = self.consecutive_error_counts.get('mvco', 0)
                should_trigger = mvco_errors >= 5

            elif switch_name == 'model_pull':
                pull_errors = self.consecutive_error_counts.get('model_pull', 0)
                should_trigger = pull_errors >= 3

            elif switch_name == 'memory_usage':
                # Already checked in _check_memory_usage
                continue

            elif switch_name == 'global_emergency':
                critical_errors = len([e for e in self.error_history
                                     if e.severity == 'critical' and
                                     time.time() - e.timestamp < 300])  # Last 5 minutes
                should_trigger = critical_errors >= 10

            if should_trigger:
                self._trigger_kill_switch(switch_name)

    def report_error(self, component: str, error_type: str, error_message: str,
                    severity: str = 'medium', auto_recover: bool = True):
        """Report a system error for tracking and potential recovery"""

        error = SystemError(
            timestamp=time.time(),
            component=component,
            error_type=error_type,
            error_message=error_message,
            severity=severity
        )

        self.error_history.append(error)
        self.component_error_counts[component] += 1
        self.consecutive_error_counts[component] += 1

        # Log error
        self._log_error(error)

        # Attempt recovery if enabled
        if auto_recover and self.hardening_config.enable_recovery_mode:
            recovery_success = self._attempt_recovery(error)
            error.recovery_attempted = True
            error.recovery_successful = recovery_success

            if recovery_success:
                self.consecutive_error_counts[component] = 0  # Reset on successful recovery

        # Check if we need to escalate
        if severity == 'critical' or self.consecutive_error_counts[component] >= self.hardening_config.max_consecutive_errors:
            self._escalate_error_handling(error)

        # Backup system state if configured
        if self.hardening_config.backup_on_errors and severity in ['high', 'critical']:
            self._backup_system_state(f"error_{component}_{error_type}")

    def _attempt_recovery(self, error: SystemError) -> bool:
        """Attempt to recover from an error"""
        recovery_key = f"{error.component}_{error.error_type}"

        if recovery_key in self.recovery_handlers:
            try:
                print(f"Hardening: Attempting recovery for {recovery_key}")
                recovery_result = self.recovery_handlers[recovery_key](error)

                if recovery_result:
                    print(f"Hardening: Recovery successful for {recovery_key}")
                    return True
                else:
                    print(f"Hardening: Recovery failed for {recovery_key}")
                    return False

            except Exception as e:
                print(f"Hardening: Recovery attempt failed with exception: {e}")
                return False

        # Generic recovery attempts
        if error.component == 'mvco' and 'thread' in error.error_type:
            return self._recover_mvco_thread()
        elif error.component == 'model_pull':
            return self._recover_model_pull(error)

        return False

    def _recover_mvco_thread(self) -> bool:
        """Attempt to recover MVCO background thread"""
        try:
            # This would be called with actual MVCO instance
            print("Hardening: Attempting MVCO thread recovery")
            # In real implementation, this would restart the thread
            return True
        except Exception:
            return False

    def _recover_model_pull(self, error: SystemError) -> bool:
        """Attempt to recover from model pull failure"""
        try:
            print("Hardening: Attempting model pull recovery using fallback")
            # In real implementation, this would trigger fallback model
            return True
        except Exception:
            return False

    def _escalate_error_handling(self, error: SystemError):
        """Escalate error handling when normal recovery fails"""
        print(f"Hardening: Escalating error handling for {error.component}:{error.error_type}")

        if error.severity == 'critical':
            self._trigger_emergency_mode(f"Critical error: {error.error_message}")
        else:
            self._trigger_safe_mode(f"Excessive errors in {error.component}")

    def _trigger_safe_mode(self, reason: str):
        """Trigger safe mode operation"""
        if not self.safe_mode_active:
            print(f"Hardening: Entering SAFE MODE - {reason}")
            self.safe_mode_active = True

            # Disable non-essential features
            self._disable_non_essential_features()

            # Log safe mode activation
            self._log_system_event('safe_mode_activated', {'reason': reason})

    def _trigger_emergency_mode(self, reason: str):
        """Trigger emergency mode operation"""
        if not self.emergency_mode_active:
            print(f"Hardening: Entering EMERGENCY MODE - {reason}")
            self.emergency_mode_active = True
            self.safe_mode_active = True

            # Emergency backup
            self._backup_system_state("emergency_backup")

            # Disable all non-critical systems
            self._trigger_kill_switch('global_emergency')

            # Log emergency mode activation
            self._log_system_event('emergency_mode_activated', {'reason': reason})

    def _trigger_kill_switch(self, switch_name: str):
        """Trigger a specific kill switch"""
        if switch_name not in self.kill_switches:
            return

        kill_switch = self.kill_switches[switch_name]
        if kill_switch.triggered:
            return

        print(f"Hardening: KILL SWITCH TRIGGERED - {switch_name}: {kill_switch.description}")

        kill_switch.triggered = True
        kill_switch.trigger_count += 1

        # Execute kill switch specific actions
        if switch_name == 'global_emergency':
            self._execute_global_emergency_shutdown()
        elif switch_name == 'mvco_thread':
            self._execute_mvco_kill_switch()
        elif switch_name == 'model_pull':
            self._execute_model_pull_kill_switch()
        elif switch_name == 'memory_usage':
            self._execute_memory_kill_switch()

        # Log kill switch activation
        self._log_system_event('kill_switch_triggered', {
            'switch_name': switch_name,
            'description': kill_switch.description,
            'trigger_count': kill_switch.trigger_count
        })

    def _execute_global_emergency_shutdown(self):
        """Execute global emergency shutdown"""
        print("Hardening: EXECUTING GLOBAL EMERGENCY SHUTDOWN")
        self.global_kill_switch_triggered = True

        # Stop all background processes
        self.monitoring_active = False

        # Backup current state
        self._backup_system_state("global_emergency_shutdown")

        # In a real implementation, this would shut down all components

    def _execute_mvco_kill_switch(self):
        """Execute MVCO kill switch"""
        print("Hardening: EXECUTING MVCO KILL SWITCH")
        # In real implementation, this would force-stop MVCO threads

    def _execute_model_pull_kill_switch(self):
        """Execute model pull kill switch"""
        print("Hardening: EXECUTING MODEL PULL KILL SWITCH")
        # In real implementation, this would disable model pulling

    def _execute_memory_kill_switch(self):
        """Execute memory usage kill switch"""
        print("Hardening: EXECUTING MEMORY KILL SWITCH")
        # In real implementation, this would free memory and reduce resource usage

    def _disable_non_essential_features(self):
        """Disable non-essential features for safe mode"""
        print("Hardening: Disabling non-essential features for safe mode")
        # In real implementation, this would disable background learning, etc.

    def _backup_system_state(self, backup_name: str):
        """Backup current system state"""
        try:
            backup_data = {
                'timestamp': time.time(),
                'datetime': datetime.now().isoformat(),
                'backup_name': backup_name,
                'error_history': [asdict(e) for e in self.error_history[-50:]],  # Last 50 errors
                'component_error_counts': dict(self.component_error_counts),
                'consecutive_error_counts': dict(self.consecutive_error_counts),
                'kill_switches': {name: asdict(switch) for name, switch in self.kill_switches.items()},
                'safe_mode_active': self.safe_mode_active,
                'emergency_mode_active': self.emergency_mode_active
            }

            backup_file = self.backup_directory / f"{backup_name}_{int(time.time())}.json"
            with open(backup_file, 'w') as f:
                json.dump(backup_data, f, indent=2)

            print(f"Hardening: System state backed up to {backup_file}")

        except Exception as e:
            print(f"Hardening: Backup failed: {e}")

    def _log_error(self, error: SystemError):
        """Log error to file"""
        try:
            log_file = Path('logs/hardening_errors.jsonl')
            log_file.parent.mkdir(parents=True, exist_ok=True)

            with open(log_file, 'a') as f:
                f.write(json.dumps(asdict(error)) + '\\n')

        except Exception as e:
            print(f"Hardening: Error logging failed: {e}")

    def _log_system_event(self, event_type: str, event_data: Dict[str, Any]):
        """Log system events"""
        try:
            log_entry = {
                'timestamp': time.time(),
                'datetime': datetime.now().isoformat(),
                'event_type': event_type,
                'event_data': event_data
            }

            log_file = Path('logs/hardening_events.jsonl')
            log_file.parent.mkdir(parents=True, exist_ok=True)

            with open(log_file, 'a') as f:
                f.write(json.dumps(log_entry) + '\\n')

        except Exception as e:
            print(f"Hardening: Event logging failed: {e}")

    def register_recovery_handler(self, component: str, error_type: str, handler: Callable):
        """Register a recovery handler for specific error types"""
        recovery_key = f"{component}_{error_type}"
        self.recovery_handlers[recovery_key] = handler
        print(f"Hardening: Registered recovery handler for {recovery_key}")

    def trigger_graceful_shutdown(self):
        """Trigger graceful system shutdown"""
        print("Hardening: Initiating graceful shutdown")

        # Backup current state
        self._backup_system_state("graceful_shutdown")

        # Stop monitoring
        self.monitoring_active = False

        # Wait for monitoring thread to finish
        if self.monitoring_thread and self.monitoring_thread.is_alive():
            self.monitoring_thread.join(timeout=self.hardening_config.thread_shutdown_timeout)

        # Log shutdown
        self._log_system_event('graceful_shutdown', {'initiated_by': 'signal_handler'})

        print("Hardening: Graceful shutdown completed")

    def get_system_status(self) -> Dict[str, Any]:
        """Get current system hardening status"""
        return {
            'safe_mode_active': self.safe_mode_active,
            'emergency_mode_active': self.emergency_mode_active,
            'global_kill_switch_triggered': self.global_kill_switch_triggered,
            'monitoring_active': self.monitoring_active,
            'total_errors': len(self.error_history),
            'component_error_counts': dict(self.component_error_counts),
            'consecutive_error_counts': dict(self.consecutive_error_counts),
            'active_kill_switches': [name for name, switch in self.kill_switches.items() if switch.triggered],
            'recent_errors': [asdict(e) for e in self.error_history[-5:]],  # Last 5 errors
            'hardening_config': asdict(self.hardening_config)
        }

    def reset_error_counts(self, component: str = None):
        """Reset error counts for recovery testing"""
        if component:
            self.consecutive_error_counts[component] = 0
            print(f"Hardening: Reset error count for {component}")
        else:
            self.consecutive_error_counts.clear()
            print("Hardening: Reset all error counts")

    def reset_kill_switches(self):
        """Reset all kill switches (for testing/recovery)"""
        for switch in self.kill_switches.values():
            switch.triggered = False
        self.global_kill_switch_triggered = False
        print("Hardening: Reset all kill switches")

# Global hardening manager instance
hardening_manager: Optional[SystemHardeningManager] = None

def initialize_hardening_manager(config: Config) -> SystemHardeningManager:
    """Initialize the global hardening manager"""
    global hardening_manager
    hardening_manager = SystemHardeningManager(config)
    return hardening_manager

def get_hardening_manager() -> Optional[SystemHardeningManager]:
    """Get the global hardening manager instance"""
    return hardening_manager